noncompliant:
void badFunction() {
  char buffer[100];  // Stack allocated
  free(buffer);  // Noncompliant: cannot free stack memory
}

void anotherBadExample(char* external_buffer) {
  // external_buffer might not be heap allocated
  free(external_buffer);  // Noncompliant: uncertain ownership
}

void usingAlloca() {
  char* temp = alloca(100);
  free(temp);  // Noncompliant: alloca memory cannot be freed
}

compliant:
void goodFunction() {
  char* buffer = malloc(100);  // Heap allocated
  if (buffer) {
    // use buffer...
    free(buffer);  // Compliant: freeing heap memory
  }
}

void managedFunction(char* buffer, bool should_free) {
  // use buffer...
  if (should_free) {
    free(buffer);  // Compliant: controlled freeing
  }
}

void stackBuffer() {
  char buffer[100];  // Stack allocated
  // use buffer...
  // No need to free - automatically cleaned up
}
